+fn count_dirty_nodes<G: DependencyGraph>(graph: &G, dirty: &DirtySet) -> usize {
+    dirty
+        .regions
+        .iter()
+        .filter_map(|region_id| graph.regions().get(region_id))
+        .flat_map(|region| region.node_indexes.iter().copied())
+        .collect::<BTreeSet<_>>()
+        .len()
+}
